/**
 * OperatingModeSelector - FULL-SCREEN Trust-Building Choice
 * 
 * This is a CRITICAL MOMENT in onboarding. The user is choosing
 * how much autonomy to give their AI. Make it feel significant.
 * 
 * Three cards, full-screen, visually distinct:
 * 🛡️ Safe & Cautious - Blue/Shield, calm
 * 🚀 Aggressive & Proactive - Orange/Red, bold, rocket
 * ⚖️ Balanced - Purple, scales, middle ground
 */

import { useState, useCallback } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Shield, Rocket, Scale, CheckCircle, Sparkles } from 'lucide-react';

export type OperatingMode = 'safe' | 'aggressive' | 'balanced';

interface OperatingModeOption {
  id: OperatingMode;
  name: string;
  tagline: string;
  description: string;
  icon: typeof Shield;
  emoji: string;
  // Colors
  bgGradient: string;
  borderColor: string;
  glowColor: string;
  iconBg: string;
  textColor: string;
  hoverGlow: string;
  selectedGlow: string;
}

const OPERATING_MODES: OperatingModeOption[] = [
  {
    id: 'safe',
    name: 'Safe & Cautious',
    tagline: "I'll always ask before taking action",
    description: 'More checkpoints, more approvals. Good if you want full control while we build trust.',
    icon: Shield,
    emoji: '🛡️',
    bgGradient: 'from-blue-950/80 via-blue-900/60 to-slate-900/80',
    borderColor: 'border-blue-500/40',
    glowColor: 'shadow-blue-500/20',
    iconBg: 'from-blue-500 to-blue-600',
    textColor: 'text-blue-400',
    hoverGlow: 'hover:shadow-blue-500/40 hover:border-blue-400/60',
    selectedGlow: 'shadow-blue-500/60 border-blue-400',
  },
  {
    id: 'aggressive',
    name: 'Aggressive & Proactive',
    tagline: "I'll take initiative... tell you after",
    description: 'Spot an opportunity? I\'ll run with it. Good if you want speed and hate micromanaging.',
    icon: Rocket,
    emoji: '🚀',
    bgGradient: 'from-orange-950/80 via-red-900/60 to-slate-900/80',
    borderColor: 'border-orange-500/40',
    glowColor: 'shadow-orange-500/20',
    iconBg: 'from-orange-500 to-red-500',
    textColor: 'text-orange-400',
    hoverGlow: 'hover:shadow-orange-500/40 hover:border-orange-400/60',
    selectedGlow: 'shadow-orange-500/60 border-orange-400',
  },
  {
    id: 'balanced',
    name: 'Balanced',
    tagline: 'Handle routine stuff on my own, check in on bigger decisions',
    description: 'A mix of both. I\'ll handle the small stuff, but loop you in for important moves.',
    icon: Scale,
    emoji: '⚖️',
    bgGradient: 'from-purple-950/80 via-violet-900/60 to-slate-900/80',
    borderColor: 'border-purple-500/40',
    glowColor: 'shadow-purple-500/20',
    iconBg: 'from-purple-500 to-violet-500',
    textColor: 'text-purple-400',
    hoverGlow: 'hover:shadow-purple-500/40 hover:border-purple-400/60',
    selectedGlow: 'shadow-purple-500/60 border-purple-400',
  },
];

interface OperatingModeSelectorProps {
  aiName: string;
  onSelect: (mode: OperatingMode) => void;
  voiceEnabled?: boolean;
  onSpeak?: (text: string) => Promise<void>;
}

// Floating particles background effect
function FloatingParticles() {
  return (
    <div className="absolute inset-0 overflow-hidden pointer-events-none">
      {[...Array(20)].map((_, i) => (
        <motion.div
          key={i}
          className="absolute w-2 h-2 rounded-full bg-white/10"
          initial={{
            x: Math.random() * 100 + '%',
            y: Math.random() * 100 + '%',
          }}
          animate={{
            y: [null, '-20%', null],
            opacity: [0.1, 0.3, 0.1],
          }}
          transition={{
            duration: 5 + Math.random() * 5,
            repeat: Infinity,
            delay: Math.random() * 5,
            ease: 'easeInOut',
          }}
        />
      ))}
    </div>
  );
}

// Selection celebration effect
function SelectionCelebration({ mode }: { mode: OperatingModeOption }) {
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 flex items-center justify-center pointer-events-none"
    >
      {/* Radial burst */}
      <motion.div
        initial={{ scale: 0, opacity: 1 }}
        animate={{ scale: [0, 15], opacity: [1, 0] }}
        transition={{ duration: 0.8, ease: 'easeOut' }}
        className={`absolute w-32 h-32 rounded-full bg-gradient-to-r ${mode.iconBg}`}
      />
      
      {/* Particle burst */}
      {[...Array(16)].map((_, i) => {
        const angle = (i / 16) * Math.PI * 2;
        const distance = 200 + Math.random() * 100;
        return (
          <motion.div
            key={i}
            initial={{ x: 0, y: 0, opacity: 1, scale: 1 }}
            animate={{
              x: Math.cos(angle) * distance,
              y: Math.sin(angle) * distance,
              opacity: 0,
              scale: 0.5,
            }}
            transition={{ duration: 0.6, ease: 'easeOut', delay: Math.random() * 0.1 }}
            className={`absolute w-4 h-4 rounded-full bg-gradient-to-r ${mode.iconBg}`}
          />
        );
      })}
      
      {/* Sparkles */}
      {[...Array(8)].map((_, i) => {
        const angle = (i / 8) * Math.PI * 2;
        const distance = 150 + Math.random() * 50;
        return (
          <motion.div
            key={`sparkle-${i}`}
            initial={{ x: 0, y: 0, opacity: 1, scale: 0 }}
            animate={{
              x: Math.cos(angle) * distance,
              y: Math.sin(angle) * distance,
              opacity: [1, 1, 0],
              scale: [0, 1.5, 1],
            }}
            transition={{ duration: 0.8, ease: 'easeOut', delay: 0.1 + i * 0.03 }}
            className="absolute"
          >
            <Sparkles className="w-6 h-6 text-yellow-400" />
          </motion.div>
        );
      })}
    </motion.div>
  );
}

// Individual mode card
function ModeCard({
  mode,
  isSelected,
  isHovered,
  onSelect,
  onHover,
  onLeave,
  disabled,
}: {
  mode: OperatingModeOption;
  isSelected: boolean;
  isHovered: boolean;
  onSelect: () => void;
  onHover: () => void;
  onLeave: () => void;
  disabled: boolean;
}) {
  const Icon = mode.icon;
  
  return (
    <motion.button
      onClick={onSelect}
      onMouseEnter={onHover}
      onMouseLeave={onLeave}
      disabled={disabled}
      className={`
        relative w-full h-full min-h-[320px] md:min-h-[400px]
        rounded-3xl border-2 p-6 md:p-8
        transition-all duration-300 ease-out
        bg-gradient-to-br ${mode.bgGradient}
        ${mode.borderColor}
        ${!disabled && !isSelected ? mode.hoverGlow : ''}
        ${isSelected ? mode.selectedGlow : ''}
        ${isSelected ? 'shadow-2xl scale-[1.02]' : 'shadow-xl'}
        ${disabled && !isSelected ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}
        group overflow-hidden
      `}
      initial={false}
      animate={{
        y: isHovered && !isSelected && !disabled ? -8 : 0,
        scale: isSelected ? 1.02 : 1,
      }}
      transition={{ type: 'spring', stiffness: 300, damping: 25 }}
      whileTap={{ scale: disabled ? 1 : 0.98 }}
    >
      {/* Glow effect on hover */}
      <motion.div
        className={`absolute inset-0 rounded-3xl bg-gradient-to-br ${mode.iconBg} opacity-0 blur-xl`}
        animate={{ opacity: isHovered && !disabled ? 0.15 : 0 }}
        transition={{ duration: 0.3 }}
      />
      
      {/* Selected checkmark */}
      <AnimatePresence>
        {isSelected && (
          <motion.div
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            exit={{ scale: 0, opacity: 0 }}
            className="absolute top-4 right-4 w-10 h-10 rounded-full bg-green-500 flex items-center justify-center shadow-lg shadow-green-500/50"
          >
            <CheckCircle className="w-6 h-6 text-white" />
          </motion.div>
        )}
      </AnimatePresence>
      
      {/* Icon */}
      <motion.div
        className={`
          relative w-20 h-20 md:w-24 md:h-24 mx-auto mb-6
          rounded-2xl bg-gradient-to-br ${mode.iconBg}
          flex items-center justify-center
          shadow-lg
        `}
        animate={{
          scale: isHovered || isSelected ? 1.1 : 1,
          rotate: isHovered && !isSelected ? [0, -5, 5, 0] : 0,
        }}
        transition={{ 
          scale: { type: 'spring', stiffness: 300, damping: 20 },
          rotate: { duration: 0.5 },
        }}
      >
        {/* Inner glow */}
        <motion.div
          className="absolute inset-0 rounded-2xl bg-white/20"
          animate={{ opacity: isHovered || isSelected ? 1 : 0 }}
        />
        <Icon className="w-10 h-10 md:w-12 md:h-12 text-white relative z-10" />
      </motion.div>
      
      {/* Emoji badge */}
      <motion.div
        className="absolute top-4 left-4 text-3xl md:text-4xl"
        animate={{
          scale: isHovered || isSelected ? 1.2 : 1,
          rotate: isHovered && !isSelected ? [0, -10, 10, 0] : 0,
        }}
        transition={{ duration: 0.3 }}
      >
        {mode.emoji}
      </motion.div>
      
      {/* Content */}
      <div className="relative z-10 text-center">
        <motion.h3
          className={`text-xl md:text-2xl font-bold mb-2 ${mode.textColor}`}
          animate={{ scale: isSelected ? 1.05 : 1 }}
        >
          {mode.name}
        </motion.h3>
        
        <motion.p
          className="text-white/90 text-sm md:text-base font-medium mb-4 leading-relaxed"
          animate={{ opacity: isHovered || isSelected ? 1 : 0.8 }}
        >
          "{mode.tagline}"
        </motion.p>
        
        <motion.p
          className="text-white/50 text-xs md:text-sm leading-relaxed"
          initial={{ opacity: 0.5 }}
          animate={{ opacity: isHovered || isSelected ? 0.8 : 0.5 }}
        >
          {mode.description}
        </motion.p>
      </div>
      
      {/* Bottom highlight line */}
      <motion.div
        className={`absolute bottom-0 left-0 right-0 h-1 bg-gradient-to-r ${mode.iconBg}`}
        initial={{ scaleX: 0 }}
        animate={{ scaleX: isSelected ? 1 : isHovered ? 0.7 : 0 }}
        transition={{ duration: 0.3 }}
        style={{ originX: 0.5 }}
      />
    </motion.button>
  );
}

export function OperatingModeSelector({
  aiName,
  onSelect,
  voiceEnabled = true,
  onSpeak,
}: OperatingModeSelectorProps) {
  const [selectedMode, setSelectedMode] = useState<OperatingMode | null>(null);
  const [hoveredMode, setHoveredMode] = useState<OperatingMode | null>(null);
  const [isConfirming, setIsConfirming] = useState(false);
  const [showCelebration, setShowCelebration] = useState(false);
  
  const handleSelect = useCallback(async (mode: OperatingMode) => {
    if (isConfirming) return;
    
    setSelectedMode(mode);
    setIsConfirming(true);
    setShowCelebration(true);
    
    const selectedOption = OPERATING_MODES.find(m => m.id === mode)!;
    
    // Voice confirmation
    if (voiceEnabled && onSpeak) {
      const confirmationMessages: Record<OperatingMode, string> = {
        safe: `${selectedOption.emoji} Safe and cautious it is! I'll always check with you before making moves. Trust is built one confirmation at a time.`,
        aggressive: `${selectedOption.emoji} Let's go! Aggressive mode activated! I'll spot opportunities and run with them. You'll hear about wins, not permissions.`,
        balanced: `${selectedOption.emoji} Balanced — perfect choice! I'll handle the routine stuff, but loop you in on the big decisions. Best of both worlds.`,
      };
      
      await onSpeak(confirmationMessages[mode]);
    }
    
    // Hide celebration after animation
    setTimeout(() => {
      setShowCelebration(false);
    }, 800);
    
    // Notify parent after voice finishes
    setTimeout(() => {
      onSelect(mode);
    }, voiceEnabled ? 2500 : 1000);
  }, [isConfirming, voiceEnabled, onSpeak, onSelect]);
  
  const selectedOption = selectedMode ? OPERATING_MODES.find(m => m.id === selectedMode) : null;
  
  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-40 bg-gradient-to-br from-slate-950 via-blue-950 to-slate-900 flex flex-col"
    >
      <FloatingParticles />
      
      {/* Celebration effect */}
      <AnimatePresence>
        {showCelebration && selectedOption && (
          <SelectionCelebration mode={selectedOption} />
        )}
      </AnimatePresence>
      
      {/* Header */}
      <motion.div
        initial={{ y: -20, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ delay: 0.2 }}
        className="text-center pt-8 md:pt-12 pb-4 px-4"
      >
        <motion.h1
          className="text-3xl md:text-5xl font-bold bg-gradient-to-r from-white via-cyan-200 to-white bg-clip-text text-transparent mb-4"
          animate={{ 
            backgroundPosition: ['0%', '100%', '0%'],
          }}
          transition={{ duration: 5, repeat: Infinity }}
          style={{ backgroundSize: '200% auto' }}
        >
          How should {aiName || 'I'} operate?
        </motion.h1>
        
        <motion.p
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 0.4 }}
          className="text-white/60 text-sm md:text-base max-w-xl mx-auto"
        >
          This sets my starting point. Don't overthink it — I'll adapt to your real preferences as we work together.
        </motion.p>
      </motion.div>
      
      {/* Cards */}
      <div className="flex-1 flex items-center justify-center px-4 pb-8">
        <div className="w-full max-w-6xl">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
            {OPERATING_MODES.map((mode, index) => (
              <motion.div
                key={mode.id}
                initial={{ y: 50, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                transition={{ delay: 0.3 + index * 0.1, type: 'spring', stiffness: 100 }}
                className="h-full"
              >
                <ModeCard
                  mode={mode}
                  isSelected={selectedMode === mode.id}
                  isHovered={hoveredMode === mode.id}
                  onSelect={() => handleSelect(mode.id)}
                  onHover={() => setHoveredMode(mode.id)}
                  onLeave={() => setHoveredMode(null)}
                  disabled={isConfirming && selectedMode !== mode.id}
                />
              </motion.div>
            ))}
          </div>
        </div>
      </div>
      
      {/* Footer hint */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        transition={{ delay: 0.8 }}
        className="text-center pb-6 px-4"
      >
        <p className="text-white/30 text-xs md:text-sm">
          Click a card to select • You can always change this later
        </p>
      </motion.div>
    </motion.div>
  );
}

export default OperatingModeSelector;
