// ============================================================================
// SMART EXTRACTION FUNCTIONS
// ============================================================================

function extractName(speech: string): string {
  if (!speech?.trim()) return '';
  
  let name = speech.trim();
  
  // Remove greetings
  name = name.replace(/^(hello|hi|hey|good morning|good afternoon|good evening)[,.\s]*/i, '');
  
  // Remove name introduction patterns
  name = name.replace(/^(my name is|i'm|i am|call me|it's|this is|the name is|you can call me|just call me|let's go with|how about|i like|i'll call you|name you)\s*/i, '');
  
  // Remove trailing pleasantries
  name = name.replace(/[,.\s]*(nice to meet you|pleased to meet you|how are you|sounds good|i think).*$/i, '');
  
  // Clean up
  name = name.replace(/[.,!?]+$/, '').trim();
  
  if (!name) return '';
  
  // Capitalize each word
  return name.split(' ')
    .filter(w => w.length > 0)
    .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
    .join(' ');
}

function parseConfirmation(speech: string): 'yes' | 'no' | 'correction' | null {
  const lower = speech.toLowerCase().trim();
  
  // Yes patterns
  if (/^(yes|yeah|yep|yup|correct|right|that's right|that's it|perfect|exactly|absolutely|sure|ok|okay|sounds good|love it|great)/.test(lower)) {
    return 'yes';
  }
  
  // No patterns  
  if (/^(no|nope|nah|wrong|incorrect|not quite|that's not|actually|wait)/.test(lower)) {
    return 'no';
  }
  
  // Short response might be a correction
  if (lower.split(/\s+/).length <= 3) {
    return 'correction';
  }
  
  return null;
}

function parsePersonalityChoice(speech: string): 'safe' | 'aggressive' | 'balanced' | null {
  const lower = speech.toLowerCase();
  
  if (/safe|cautious|careful|control|approvals?|ask first|check/.test(lower)) return 'safe';
  if (/aggressive|proactive|fast|speed|initiative|run with it|autonomous/.test(lower)) return 'aggressive';
  if (/balanced|mix|middle|both|depends|routine/.test(lower)) return 'balanced';
  
  // Default to balanced if unclear
  if (lower.length > 5) return 'balanced';
  
  return null;
}

// Detect if user gave a surface-level answer that needs digging
function needsDeepDive(speech: string): boolean {
  const lower = speech.toLowerCase();
  const vagueTerms = [
    'underwater', 'mess', 'behind', 'struggling', 'busy', 
    'overwhelmed', 'growing pains', 'chaos', 'hectic', 'crazy',
    'a lot', 'tons of', 'so much', 'issues', 'problems'
  ];
  
  return vagueTerms.some(term => lower.includes(term));
}

