// Map conversation phases to progress bar steps
function getProgressPhaseIndex(phase: ConversationPhase): number {
  const phaseMapping: Record<ConversationPhase, number> = {
    'intro': 0,
    'naming': 0,
    'personality': 0,
    'company': 1,
    'reflect': 1,
    'pull_more': 1,
    'sensitive': 1,
    'kpis': 1,
    'dig_deeper': 1,
    'departments': 2,
    'deployment': 2,
    'complete': 2,
  };
  return phaseMapping[phase] ?? 0;
}

function PhaseProgress({ phases, currentPhaseIndex }: { phases: OnboardingPhase[]; currentPhaseIndex: number }) {
  const icons = {
    sparkles: Sparkles,
    building: Building2,
    users: Users,
  };

  return (
    <motion.div 
      initial={{ opacity: 0, y: -20 }}
      animate={{ opacity: 1, y: 0 }}
      className="w-full px-2"
    >
      <div className="flex items-center justify-between relative">
        {/* Progress line */}
        <div className="absolute top-6 left-8 right-8 h-1 bg-slate-700/50 rounded-full" />
        <motion.div 
          className="absolute top-6 left-8 h-1 bg-gradient-to-r from-cyan-500 via-blue-500 to-purple-500 rounded-full shadow-lg shadow-cyan-500/30"
          initial={{ width: 0 }}
          animate={{ width: `${Math.min((currentPhaseIndex / (phases.length - 1)) * 100, 100)}%` }}
          transition={{ duration: 0.7, ease: 'easeOut' }}
          style={{ maxWidth: 'calc(100% - 4rem)' }}
        />

        {phases.map((phase, idx) => {
          const Icon = icons[phase.icon];
          const isActive = idx === currentPhaseIndex;
          const isComplete = idx < currentPhaseIndex;
          const isFuture = idx > currentPhaseIndex;

          return (
            <div key={phase.id} className="flex flex-col items-center relative z-10 flex-1">
              <motion.div
                animate={{ scale: isActive ? 1.1 : 1, opacity: isFuture ? 0.4 : 1 }}
                className="relative"
              >
                {isActive && (
                  <motion.div
                    animate={{ scale: [1, 1.4, 1], opacity: [0.5, 0.2, 0.5] }}
                    transition={{ duration: 2, repeat: Infinity }}
                    className="absolute inset-0 bg-cyan-500 rounded-full blur-xl"
                  />
                )}
                
                <div className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
                  isComplete ? 'bg-gradient-to-r from-green-500 to-emerald-500' :
                  isActive ? 'bg-gradient-to-r from-cyan-500 to-blue-500 shadow-lg shadow-cyan-500/50' :
                  'bg-slate-800 border border-slate-600/50'
                }`}>
                  {isComplete ? <CheckCircle className="w-5 h-5 text-white" /> : <Icon className="w-5 h-5 text-white" />}
                </div>
              </motion.div>

              <div className="mt-3 text-center">
                <div className={`text-xs font-semibold ${isActive ? 'text-cyan-400' : isComplete ? 'text-white/80' : 'text-slate-500'}`}>
                  Step {idx + 1}
                </div>
                <div className={`text-[10px] md:text-xs mt-0.5 max-w-[100px] ${isActive ? 'text-white' : 'text-slate-500'}`}>
                  {phase.name}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </motion.div>
  );
}

