// ============================================================================
// SIMPLE ORB
// ============================================================================

function SimpleOrb({ 
  size = 180,
  isSpeaking = false,
  isListening = false,
  energy = 0.5,
}: { 
  size?: number;
  isSpeaking?: boolean;
  isListening?: boolean;
  energy?: number;
}) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    
    let animationId: number;
    let time = 0;
    
    const animate = () => {
      time += 0.02;
      ctx.clearRect(0, 0, size, size);
      
      const centerX = size / 2;
      const centerY = size / 2;
      const baseRadius = size * 0.35;
      
      // Outer glow
      const gradient = ctx.createRadialGradient(
        centerX, centerY, baseRadius * 0.5,
        centerX, centerY, baseRadius * 1.5
      );
      gradient.addColorStop(0, `rgba(6, 182, 212, ${0.2 + energy * 0.3})`);
      gradient.addColorStop(0.5, `rgba(59, 130, 246, ${0.1 + energy * 0.2})`);
      gradient.addColorStop(1, 'rgba(0, 0, 0, 0)');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, size, size);
      
      // Core orb with pulsing
      const pulseAmount = isSpeaking ? 0.15 : isListening ? 0.1 : 0.03;
      const pulseSpeed = isSpeaking ? 8 : isListening ? 5 : 3;
      const pulse = 1 + Math.sin(time * pulseSpeed) * pulseAmount;
      
      const coreGradient = ctx.createRadialGradient(
        centerX - baseRadius * 0.2, centerY - baseRadius * 0.2, 0,
        centerX, centerY, baseRadius * pulse
      );
      coreGradient.addColorStop(0, 'rgba(255, 255, 255, 0.9)');
      coreGradient.addColorStop(0.3, `rgba(6, 182, 212, ${0.8 + energy * 0.2})`);
      coreGradient.addColorStop(0.7, `rgba(59, 130, 246, ${0.7 + energy * 0.2})`);
      coreGradient.addColorStop(1, `rgba(139, 92, 246, ${0.6 + energy * 0.2})`);
      
      ctx.beginPath();
      ctx.arc(centerX, centerY, baseRadius * pulse, 0, Math.PI * 2);
      ctx.fillStyle = coreGradient;
      ctx.fill();
      
      // Listening indicator ring
      if (isListening) {
        ctx.beginPath();
        ctx.arc(centerX, centerY, baseRadius * 1.2 + Math.sin(time * 3) * 5, 0, Math.PI * 2);
        ctx.strokeStyle = 'rgba(239, 68, 68, 0.5)';
        ctx.lineWidth = 3;
        ctx.stroke();
      }
      
      // Sparkle particles
      const particleCount = Math.floor(5 + energy * 10);
      for (let i = 0; i < particleCount; i++) {
        const angle = (i / particleCount) * Math.PI * 2 + time;
        const dist = baseRadius * (0.8 + Math.sin(time * 2 + i) * 0.3);
        const x = centerX + Math.cos(angle) * dist;
        const y = centerY + Math.sin(angle) * dist;
        const particleSize = 2 + Math.sin(time * 3 + i * 2) * 1;
        
        ctx.beginPath();
        ctx.arc(x, y, particleSize, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 255, ${0.5 + Math.sin(time + i) * 0.3})`;
        ctx.fill();
      }
      
      animationId = requestAnimationFrame(animate);
    };
    
    animate();
    
    return () => cancelAnimationFrame(animationId);
  }, [size, isSpeaking, isListening, energy]);
  
  return (
    <canvas
      ref={canvasRef}
      width={size}
      height={size}
      className="mx-auto"
    />
  );
}

// ============================================================================
// MAIN COMPONENT
// ============================================================================

interface ConversationalOnboardingProps {
  onComplete: (data: {
    aiName: string;
    personality: 'safe' | 'aggressive' | 'balanced';
    context: ContextItem[];
    departments: DepartmentContext[];
  }) => void;
  voiceEnabled?: boolean;
  onVoiceToggle?: () => void;
  // Issue #2 Fix: Callback to switch to form mode at any point
  onSwitchToForm?: (collectedData: {
    aiName: string;
    personality: 'safe' | 'aggressive' | 'balanced' | null;
    context: ContextItem[];
  }) => void;
  // Issue #2 Fix: Callback to skip to org builder at any point
  onSkipToOrgBuilder?: (collectedData: {
    aiName: string;
    personality: 'safe' | 'aggressive' | 'balanced' | null;
    context: ContextItem[];
  }) => void;
}

export function ConversationalOnboarding({ 
  onComplete,
  voiceEnabled = true,
  onVoiceToggle,
  onSwitchToForm,
  onSkipToOrgBuilder,
}: ConversationalOnboardingProps) {
  // Core state
  const [messages, setMessages] = useState<Message[]>([]);
  const [phase, setPhase] = useState<ConversationPhase>('intro');
  const [isListening, setIsListening] = useState(false);
  const [inputText, setInputText] = useState('');
  
  // Collected data
  const [aiName, setAiName] = useState('');
  const [pendingName, setPendingName] = useState('');
  const [personality, setPersonality] = useState<'safe' | 'aggressive' | 'balanced' | null>(null);
  const [contextItems, setContextItems] = useState<ContextItem[]>([]);
  const [departments, setDepartments] = useState<DepartmentContext[]>([]);
  const [ownerScore, setOwnerScore] = useState(15); // Start low
  
  // Operating Mode Selector state - PROMINENT full-screen experience
  const [showOperatingModeSelector, setShowOperatingModeSelector] = useState(false);
  
  // Refs
  const recognitionRef = useRef<any>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const hasStartedRef = useRef(false);
  const dataFlowRef = useRef<DataFlowAnimationRef | null>(null);
  const orbContainerRef = useRef<HTMLDivElement>(null);
  const notesPanelRef = useRef<HTMLDivElement>(null);
  const chatContainerRef = useRef<HTMLDivElement>(null);
  
  // TTS
  const tts = useElevenLabsTTS({
    defaultVoiceId: DEFAULT_VOICE_ID,
  });

  // Auto-scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Add a message to the chat
  const addMessage = useCallback((role: 'user' | 'assistant', content: string) => {
    const msg: Message = {
      id: `${Date.now()}-${Math.random()}`,
      role,
      content,
      timestamp: new Date(),
    };
    setMessages(prev => [...prev, msg]);
    return msg;
  }, []);

  // Add context item with visual animation
  const addContext = useCallback((item: Omit<ContextItem, 'id'>) => {
    const newItem: ContextItem = {
      ...item,
      id: `ctx-${Date.now()}-${Math.random()}`,
    };
    setContextItems(prev => [...prev, newItem]);
    
    // Increase owner score
    setOwnerScore(prev => Math.min(prev + 8, 95));
    
    // 🚀 TRIGGER INSIGHT ANIMATION: Insight flies from orb to notes panel
    setTimeout(() => {
      dataFlowRef.current?.triggerInsightFromOrb(item.text);
    }, 300);
    
    return newItem;
  }, []);

  // AI speaks (voice + text) - Bug Fix #2: Text displayed MATCHES what's spoken
  const aiSpeak = useCallback(async (text: string, _voiceText?: string) => {
    // Bug Fix #2: Always display AND speak the same text
    // Ignore voiceText parameter - use text for both display and speech
    addMessage('assistant', text);
    
    if (voiceEnabled) {
      await tts.speak(text); // Always speak what's displayed
    }
  }, [addMessage, voiceEnabled, tts]);

  // Setup speech recognition
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition = (window as any).webkitSpeechRecognition || (window as any).SpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = true;
      
      recognitionRef.current.onresult = (event: any) => {
        const transcript = Array.from(event.results)
          .map((result: any) => result[0].transcript)
          .join('');
        
        setInputText(transcript);
        
        if (event.results[0].isFinal) {
          setIsListening(false);
          if (transcript.trim()) {
            handleUserInput(transcript.trim());
            setInputText('');
          }
        }
      };
      
      recognitionRef.current.onerror = () => setIsListening(false);
      recognitionRef.current.onend = () => setIsListening(false);
    }
    
    return () => {
      if (recognitionRef.current) {
        try { recognitionRef.current.stop(); } catch {}
      }
    };
  }, []);

  // Start listening
  const startListening = useCallback(() => {
    if (recognitionRef.current && !isListening) {
      try {
        recognitionRef.current.start();
        setIsListening(true);
      } catch (e) {
        console.log('[Voice] Could not start recognition:', e);
      }
    }
  }, [isListening]);

  // Stop listening
  const stopListening = useCallback(() => {
    if (recognitionRef.current && isListening) {
      recognitionRef.current.stop();
      setIsListening(false);
    }
  }, [isListening]);

  // Handle user input (voice or text)
  const handleUserInput = useCallback(async (input: string) => {
    addMessage('user', input);
    
    // 🚀 TRIGGER MESSAGE TO ORB ANIMATION: Message flies to orb (ingestion)
    setTimeout(() => {
      dataFlowRef.current?.triggerMessageToOrb(input);
    }, 100);
    
    // Process based on current phase
    switch (phase) {
      case 'intro': {
        // They said they're ready, move to naming
        setPhase('naming');
        await aiSpeak(NAMING_PROMPT);
        // Bug Fix #3: NO auto-start listening - user must click mic button
        break;
      }
      
      case 'naming': {
        // Check if confirming a pending name
        if (pendingName) {
          const confirmation = parseConfirmation(input);
          
          if (confirmation === 'yes') {
            // Bug Fix #4: Clear pending name BEFORE setting AI name to prevent loop
            const confirmedName = pendingName;
            setPendingName('');
            setAiName(confirmedName);
            addContext({ category: 'identity', label: 'Name', text: confirmedName, confidence: 1 });
            
            // PROMINENT Operating Mode Selector - full-screen card selection
            // Instead of chat-based personality selection, show the visual card selector
            setPhase('personality');
            setShowOperatingModeSelector(true);
            
            // Brief voice intro before showing the selector
            await aiSpeak(`${confirmedName}! I love it! Now let's talk about how you want me to operate.`);
            // Bug Fix #3: NO auto-start listening - cards will be clicked
          } else if (confirmation === 'correction') {
            const newName = extractName(input);
            if (newName) {
              setPendingName(newName);
              await aiSpeak(`Oh, ${newName}! Is that right?`);
              // Bug Fix #3: NO auto-start listening
            } else {
              setPendingName('');
              await aiSpeak("Okay, no problem! What name would you like?");
              // Bug Fix #3: NO auto-start listening
            }
          } else {
            setPendingName('');
            await aiSpeak("Okay! What name would you like to give me?");
            // Bug Fix #3: NO auto-start listening
          }
        } else {
          // Extract name from input
          const name = extractName(input);
          if (name) {
            setPendingName(name);
            await aiSpeak(`${name}... I love that name! Is that right?`);
            // Bug Fix #3: NO auto-start listening
          } else {
            await aiSpeak("I didn't quite catch that. What would you like to call me?");
            // Bug Fix #3: NO auto-start listening
          }
        }
        break;
      }
      
      case 'personality': {
        const choice = parsePersonalityChoice(input);
        if (choice) {
          setPersonality(choice);
          addContext({ 
            category: 'identity', 
            label: 'Operating Mode', 
            text: choice === 'safe' ? 'Safe & Cautious' : choice === 'aggressive' ? 'Aggressive & Proactive' : 'Balanced',
            confidence: 1 
          });
          setPhase('company');
          await aiSpeak(COMPANY_PROMPT(aiName, choice));
          // Bug Fix #3: NO auto-start listening
        } else {
          await aiSpeak("Would you prefer safe and cautious, aggressive and proactive, or balanced?");
          // Bug Fix #3: NO auto-start listening
        }
        break;
      }
      
      case 'company': {
        // Extract company info
        addContext({ category: 'company', label: 'Company Info', text: input, confidence: 0.9 });
        
        // Check if they need deeper probing
        if (needsDeepDive(input)) {
          setPhase('dig_deeper');
          const therapistKey = Object.keys(THERAPIST_PROMPTS).find(key => 
            input.toLowerCase().includes(key)
          ) || 'default';
          await aiSpeak(THERAPIST_PROMPTS[therapistKey]);
          // Bug Fix #3: NO auto-start listening
        } else {
          // Reflect back and pull for more
          setPhase('pull_more');
          const reflection = `I'm hearing you. Let me make sure I've got this right.\n\n${input.slice(0, 200)}${input.length > 200 ? '...' : ''}\n\n${PULL_MORE_PROMPT}`;
          await aiSpeak(reflection);
          // Bug Fix #3: NO auto-start listening
        }
        break;
      }
      
      case 'dig_deeper': {
        // They gave more detail, save it
        addContext({ category: 'challenges', label: 'Pain Points', text: input, confidence: 0.85 });
        setPhase('pull_more');
        await aiSpeak(PULL_MORE_PROMPT);
        // Bug Fix #3: NO auto-start listening
        break;
      }
      
      case 'pull_more': {
        // They shared more (or said no)
        if (input.toLowerCase().match(/^(no|nope|nothing|that's it|that's all|we're good)/)) {
          setPhase('sensitive');
          await aiSpeak(SENSITIVE_PROMPT);
          // Bug Fix #3: NO auto-start listening
        } else {
          // They shared more context
          addContext({ category: 'company', label: 'Additional Context', text: input, confidence: 0.8 });
          setPhase('sensitive');
          await aiSpeak(`Got it. I'll keep that in mind.\n\n${SENSITIVE_PROMPT}`);
          // Bug Fix #3: NO auto-start listening
        }
        break;
      }
      
      case 'sensitive': {
        if (input.trim()) {
          addContext({ category: 'sensitive', label: 'Protected Topics', text: input, confidence: 1 });
        }
        setPhase('kpis');
        await aiSpeak(`Understood. I'll handle those carefully.\n\n${KPIS_PROMPT(aiName)}`);
        // Bug Fix #3: NO auto-start listening
        break;
      }
      
      case 'kpis': {
        addContext({ category: 'goals', label: 'Success Metrics', text: input, confidence: 0.9 });
        setPhase('departments');
        await aiSpeak(`I hear you. You want proof of value — money found, employees transformed, departments leveled up.\n\nNow let's build your organization. Tell me about your team structure. Which departments do you have? Start with the ones most important to you.`);
        // Bug Fix #3: NO auto-start listening
        break;
      }
      
      case 'departments': {
        // Extract department info
        addContext({ category: 'team', label: 'Team Structure', text: input, confidence: 0.85 });
        
        // This could continue but for now move to complete
        setPhase('deployment');
        // Issue #5 Fix: Add context meeting scheduling message
        const companyName = contextItems.find(c => c.category === 'company')?.text?.match(/(?:called|named|is)\s+(\w+)|^(\w+)/i)?.[1] || 'your company';
        await aiSpeak(`Excellent. I'm building a picture of your organization. 🏗️\n\nI have enough to start being useful. I'll reach out to the key people you mentioned and start learning about their specific needs.\n\nOne more thing — I'll schedule weekly context meetings with you to continue learning about ${companyName} from your perspective as the owner. The more I understand, the more valuable I become. 📅\n\n${aiName} is ready to work. Let's build your AI team! 🚀`);
        
        // Complete after delay
        setTimeout(() => {
          setPhase('complete');
          onComplete({
            aiName,
            personality: personality!,
            context: contextItems,
            departments,
          });
        }, 4000);
        break;
      }
      
      default:
        break;
    }
  }, [phase, pendingName, aiName, personality, contextItems, departments, addMessage, addContext, aiSpeak, startListening, onComplete]);

  // Start the conversation on mount
  useEffect(() => {
    if (hasStartedRef.current) return;
    hasStartedRef.current = true;
    
    const startConversation = async () => {
      await new Promise(r => setTimeout(r, 500));
      await aiSpeak(INTRO_SCRIPT);
      // Bug Fix #3: NO auto-start listening - user must click mic button
    };
    
    startConversation();
  }, [aiSpeak]);

  // Handle text submit
  const handleTextSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputText.trim()) {
      handleUserInput(inputText.trim());
      setInputText('');
    }
  };

  // Calculate energy based on progress
  const energy = 0.3 + (contextItems.length * 0.05) + (phase === 'complete' ? 0.3 : 0);

  // State for orb animation pulses
  const [orbIngestPulse, setOrbIngestPulse] = useState(false);
  const [orbReleasePulse, setOrbReleasePulse] = useState(false);

  // Orb animation handlers
  const handleOrbIngest = useCallback(() => {
    setOrbIngestPulse(true);
    setTimeout(() => setOrbIngestPulse(false), 600);
  }, []);

  const handleOrbRelease = useCallback(() => {
    setOrbReleasePulse(true);
    setTimeout(() => setOrbReleasePulse(false), 600);
  }, []);

  // Handler for Operating Mode selection from full-screen card selector
  const handleOperatingModeSelect = useCallback(async (mode: OperatingMode) => {
    setPersonality(mode);
    setShowOperatingModeSelector(false);
    
    // Add context item
    addContext({ 
      category: 'identity', 
      label: 'Operating Mode', 
      text: mode === 'safe' ? 'Safe & Cautious' : mode === 'aggressive' ? 'Aggressive & Proactive' : 'Balanced',
      confidence: 1 
    });
    
    // Move to company phase and speak the prompt
    setPhase('company');
    
    // Add a message to the chat showing the selection
    addMessage('assistant', COMPANY_PROMPT(aiName, mode));
    
    // Voice the company prompt
    if (voiceEnabled) {
      await tts.speak(COMPANY_VOICE(mode));
    }
  }, [addContext, addMessage, aiName, voiceEnabled, tts]);

  // TTS speak function for the operating mode selector
  const handleSelectorSpeak = useCallback(async (text: string) => {
    if (voiceEnabled) {
      await tts.speak(text);
    }
  }, [voiceEnabled, tts]);

  return (
    <DataFlowAnimation
      onOrbIngest={handleOrbIngest}
      onOrbRelease={handleOrbRelease}
    >
      {(animationRef) => {
        // Store ref for use in callbacks
        dataFlowRef.current = animationRef;
        
        return (
    <>
      {/* PROMINENT Operating Mode Selector - Full-screen card experience */}
      <AnimatePresence>
        {showOperatingModeSelector && (
          <OperatingModeSelector
            aiName={aiName}
            onSelect={handleOperatingModeSelect}
            voiceEnabled={voiceEnabled}
            onSpeak={handleSelectorSpeak}
          />
        )}
      </AnimatePresence>
      
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-blue-950 to-slate-900 p-4 md:p-8">
      {/* Bug Fix #6: Progress bar at top */}
      <div className="fixed top-0 left-0 right-0 z-50 p-4 bg-gradient-to-b from-slate-950 to-transparent">
        <div className="max-w-4xl mx-auto">
          <PhaseProgress phases={ONBOARDING_PHASES} currentPhaseIndex={getProgressPhaseIndex(phase)} />
        </div>
      </div>
      
      <div className="max-w-6xl mx-auto pt-24"> {/* Added pt-24 for progress bar space */}
        <div className="grid md:grid-cols-3 gap-6">
          {/* Left: Orb + Context */}
          <div className="md:col-span-1 space-y-4">
            <div 
              ref={(el) => {
                if (el) {
                  (orbContainerRef as any).current = el;
                  animationRef.setOrbRef(el);
                }
              }}
              className="bg-slate-900/50 backdrop-blur-xl rounded-2xl border border-cyan-500/20 p-6 flex flex-col items-center"
            >
              <SimpleOrb 
                size={180}
                isSpeaking={tts.isSpeaking || orbIngestPulse || orbReleasePulse}
                isListening={isListening}
                energy={energy + (orbIngestPulse ? 0.3 : 0) + (orbReleasePulse ? 0.2 : 0)}
              />
              <div className="mt-4 text-center">
                <div className="text-white font-medium text-lg">
                  {aiName || 'Your AI'}
                </div>
                <div className="text-cyan-400/70 text-sm">
                  {tts.isSpeaking ? '🔊 Speaking...' : isListening ? '🎤 Listening...' : 'Ready'}
                </div>
              </div>
            </div>
            
            {/* Context scores or What I Learned */}
            <div
              ref={(el) => {
                if (el) {
                  (notesPanelRef as any).current = el;
                  animationRef.setNotesRef(el);
                }
              }}
            >
              {contextItems.length > 3 ? (
                <ContextScoresPanel 
                  aiName={aiName}
                  ownerScore={ownerScore}
                  departments={departments}
                />
              ) : (
                <WhatILearnedPanel items={contextItems} aiName={aiName} />
              )}
            </div>
          </div>

          {/* Right: Chat */}
          <div 
            ref={(el) => {
              if (el) {
                (chatContainerRef as any).current = el;
                animationRef.setChatRef(el);
              }
            }}
            className="md:col-span-2 bg-slate-900/50 backdrop-blur-xl rounded-2xl border border-cyan-500/20 flex flex-col h-[600px]"
          >
            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              <AnimatePresence>
                {messages.map((msg) => (
                  <motion.div
                    key={msg.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
                  >
                    <div className={`max-w-[85%] rounded-2xl px-4 py-3 ${
                      msg.role === 'user' 
                        ? 'bg-gradient-to-r from-cyan-500/20 to-blue-500/20 border border-cyan-500/30' 
                        : 'bg-slate-800/80'
                    }`}>
                      <p className="text-white/90 text-sm whitespace-pre-wrap leading-relaxed">
                        {msg.content}
                      </p>
                    </div>
                  </motion.div>
                ))}
              </AnimatePresence>
              
              {/* Typing indicator */}
              {tts.isSpeaking && (
                <motion.div 
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="flex justify-start"
                >
                  <div className="bg-slate-800/80 rounded-2xl px-4 py-3">
                    <div className="flex gap-1.5">
                      {[0, 1, 2].map(i => (
                        <motion.div
                          key={i}
                          animate={{ y: [0, -6, 0] }}
                          transition={{ duration: 0.6, repeat: Infinity, delay: i * 0.15 }}
                          className="w-2.5 h-2.5 bg-cyan-400 rounded-full"
                        />
                      ))}
                    </div>
                  </div>
                </motion.div>
              )}
              
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <form onSubmit={handleTextSubmit} className="p-4 border-t border-slate-700/50">
              <div className="flex gap-3">
                {/* Mic button */}
                <motion.button
                  type="button"
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                  onClick={isListening ? stopListening : startListening}
                  className={`w-12 h-12 rounded-full flex items-center justify-center transition-all ${
                    isListening 
                      ? 'bg-red-500 text-white shadow-lg shadow-red-500/50 animate-pulse' 
                      : 'bg-slate-700 text-slate-300 hover:bg-cyan-500 hover:text-white'
                  }`}
                >
                  {isListening ? <Mic className="w-5 h-5" /> : <MicOff className="w-5 h-5" />}
                </motion.button>
                
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder={isListening ? "Listening..." : "Type or speak..."}
                  className="flex-1 bg-slate-800 border border-slate-600 rounded-xl px-4 py-3 text-white placeholder:text-slate-500 focus:outline-none focus:border-cyan-500 transition-colors"
                  disabled={isListening}
                />
                
                <motion.button
                  type="submit"
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                  disabled={!inputText.trim() || isListening}
                  className="bg-gradient-to-r from-cyan-500 to-blue-500 text-white px-5 py-3 rounded-xl disabled:opacity-50 transition-all"
                >
                  <Send className="w-5 h-5" />
                </motion.button>
              </div>
              
              <p className="text-center text-white/30 text-xs mt-2">
                {isListening ? '🎤 Speak naturally...' : 'Click the mic or type your response'}
              </p>
            </form>
          </div>
        </div>
      </div>
      
      {/* Voice toggle */}
      <button
        onClick={onVoiceToggle}
        className="fixed bottom-6 left-6 z-50 flex items-center gap-2 px-4 py-2 bg-slate-800/80 backdrop-blur rounded-full text-sm text-white/70 hover:text-white transition-colors"
      >
        {voiceEnabled ? <Volume2 className="w-4 h-4" /> : <VolumeX className="w-4 h-4" />}
        {voiceEnabled ? 'Voice On' : 'Voice Off'}
      </button>
      
      {/* Issue #2 Fix: Form mode / Skip to Org Builder - works at ANY point, preserves answers */}
      <div className="fixed bottom-6 right-6 z-50 flex items-center gap-3">
        <button
          onClick={() => { 
            // Issue #2 Fix: Use callback to preserve state instead of page reload
            if (onSwitchToForm) {
              onSwitchToForm({
                aiName: aiName || '',
                personality: personality,
                context: contextItems,
              });
            } else {
              // Fallback: navigate with context preserved
              const contextData = encodeURIComponent(JSON.stringify({
                aiName: aiName || '',
                personality: personality || 'balanced',
                context: contextItems,
              }));
              window.location.hash = `#/plankbeam?mode=form&context=${contextData}`;
            }
          }}
          className="flex items-center gap-2 px-4 py-2 bg-slate-800/80 backdrop-blur rounded-full text-sm text-white/50 hover:text-white transition-colors cursor-pointer"
        >
          <FileText className="w-4 h-4" />
          Form mode
        </button>
        <button
          onClick={() => { 
            // Issue #2 Fix: Use callback to preserve state instead of page reload
            if (onSkipToOrgBuilder) {
              onSkipToOrgBuilder({
                aiName: aiName || '',
                personality: personality,
                context: contextItems,
              });
            } else {
              // Fallback: navigate with context preserved
              const contextData = encodeURIComponent(JSON.stringify({
                aiName: aiName || 'Scout',
                personality: personality || 'balanced',
                context: contextItems,
              }));
              window.location.hash = `#/plankbeam?step=orgbuilder&context=${contextData}`;
            }
          }}
          className="flex items-center gap-2 px-4 py-2 bg-slate-800/80 backdrop-blur rounded-full text-sm text-white/50 hover:text-white transition-colors cursor-pointer"
        >
          Skip to Org Builder
          <ArrowRight className="w-4 h-4" />
        </button>
      </div>
    </div>
    </>
        );
      }}
    </DataFlowAnimation>
  );
}

export default ConversationalOnboarding;
