// ============================================================================
// SMART NAME EXTRACTION - Parse natural speech into just the name
// ============================================================================

function extractNameFromSpeech(speech: string): string {
  if (!speech || !speech.trim()) return '';
  
  let name = speech.trim();
  
  // Remove greetings at the start
  name = name.replace(/^(hello|hi|hey|good morning|good afternoon|good evening)[,.\s]*/i, '');
  
  // Remove common name introduction patterns
  name = name.replace(/^(my name is|i'm|i am|call me|it's|this is|the name is|you can call me|just call me)\s*/i, '');
  
  // Remove trailing pleasantries
  name = name.replace(/[,.\s]*(nice to meet you|pleased to meet you|how are you).*$/i, '');
  
  // Clean up punctuation and extra spaces
  name = name.replace(/[.,!?]+$/, '').trim();
  
  // If nothing left, return empty
  if (!name) return '';
  
  // Capitalize first letter of each word
  return name.split(' ').map(word => 
    word.charAt(0).toUpperCase() + word.slice(1).toLowerCase()
  ).join(' ');
}

// Check if speech is a confirmation (yes/no/correction)
function parseConfirmation(speech: string): 'yes' | 'no' | 'correction' | null {
  const lower = speech.toLowerCase().trim();
  
  // Yes patterns
  if (/^(yes|yeah|yep|yup|correct|right|that's right|that's it|perfect|exactly|absolutely|sure|ok|okay|affirmative)/.test(lower)) {
    return 'yes';
  }
  
  // No patterns
  if (/^(no|nope|nah|wrong|incorrect|not quite|that's not|actually)/.test(lower)) {
    return 'no';
  }
  
  // If it's short and has a name-like pattern, it might be a correction
  const words = lower.split(/\s+/);
  if (words.length <= 4) {
    return 'correction';
  }
  
  return null;
}

