// Shuffle function for idle messages
function shuffleArray<T>(array: T[]): T[] {
  const shuffled = [...array];
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
  }
  return shuffled;
}

// ============================================================================
// STARBURST PARTICLE EFFECT - Background atmosphere behind orb
// ============================================================================

// Issue #1 Fix: Smoother starburst animation with better easing and timing
function StarburstEffect({ active, intensity = 1 }: { active: boolean; intensity?: number }) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const animationRef = useRef<number>();
  const particlesRef = useRef<Array<{
    x: number;
    y: number;
    angle: number;
    speed: number;
    size: number;
    hue: number;
    life: number;
    maxLife: number;
    startTime: number;
  }>>([]);
  const lastTimeRef = useRef<number>(0);
  const startTimeRef = useRef<number>(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: true });
    if (!ctx) return;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    resize();
    window.addEventListener('resize', resize);

    const particles = particlesRef.current;
    const centerX = () => canvas.width / 2;
    const centerY = () => canvas.height / 2;
    
    // Max particles for performance
    const MAX_PARTICLES = 40;

    // Smooth easing function (ease-out-cubic)
    const easeOutCubic = (t: number) => 1 - Math.pow(1 - t, 3);
    
    // Smooth easing function (ease-in-out-sine)
    const easeInOutSine = (t: number) => -(Math.cos(Math.PI * t) - 1) / 2;

    const animate = (timestamp: number) => {
      if (!startTimeRef.current) startTimeRef.current = timestamp;
      
      // Calculate delta time for smooth animation
      const deltaTime = timestamp - lastTimeRef.current;
      lastTimeRef.current = timestamp;
      
      // Skip frame if delta is too large (tab was inactive) - prevents jumps
      if (deltaTime > 50) {
        animationRef.current = requestAnimationFrame(animate);
        return;
      }
      
      // Use fixed time step for consistent physics (smoother than variable delta)
      const fixedDelta = 16.67; // 60fps target
      const deltaFactor = Math.min(deltaTime / fixedDelta, 2); // Cap at 2x to prevent jumps
      
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      // Spawn new particles from center (smoother spawn rate)
      if (active && particles.length < MAX_PARTICLES && Math.random() < 0.1 * intensity) {
        const angle = Math.random() * Math.PI * 2;
        particles.push({
          x: centerX(),
          y: centerY(),
          angle,
          speed: 0.5 + Math.random() * 1.2 * intensity, // Slower, smoother movement
          size: 1.5 + Math.random() * 2,
          hue: 180 + Math.random() * 60, // Cyan to blue range
          life: 1,
          maxLife: 80 + Math.random() * 80, // Longer life for smoother fade
          startTime: timestamp,
        });
      }

      // Batch draw operations
      ctx.globalCompositeOperation = 'lighter';
      
      // Update and draw particles with smooth interpolation
      for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];
        
        // Calculate life progress (0 to 1)
        const lifeProgress = 1 - p.life;
        
        // Apply easing to movement speed (starts fast, slows down)
        const easedSpeed = p.speed * (1 - easeOutCubic(lifeProgress) * 0.7);
        
        // Move outward from center with smooth eased movement
        p.x += Math.cos(p.angle) * easedSpeed * deltaFactor;
        p.y += Math.sin(p.angle) * easedSpeed * deltaFactor;
        p.life -= (1 / p.maxLife) * deltaFactor;

        if (p.life <= 0) {
          particles.splice(i, 1);
          continue;
        }

        // Apply easing to alpha (smooth fade out)
        const alpha = easeInOutSine(p.life) * 0.5;
        
        // Single glow + core combined with smooth gradient
        const gradient = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size * 3);
        gradient.addColorStop(0, `hsla(${p.hue}, 80%, 80%, ${alpha})`);
        gradient.addColorStop(0.4, `hsla(${p.hue}, 80%, 60%, ${alpha * 0.4})`);
        gradient.addColorStop(1, `hsla(${p.hue}, 80%, 50%, 0)`);
        
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.size * 3, 0, Math.PI * 2);
        ctx.fillStyle = gradient;
        ctx.fill();
      }
      
      ctx.globalCompositeOperation = 'source-over';

      animationRef.current = requestAnimationFrame(animate);
    };

    animationRef.current = requestAnimationFrame(animate);

    return () => {
      window.removeEventListener('resize', resize);
      if (animationRef.current) cancelAnimationFrame(animationRef.current);
      particlesRef.current = [];
    };
  }, [active, intensity]);

  return (
    <canvas
      ref={canvasRef}
      className="fixed inset-0 pointer-events-none"
      style={{ zIndex: 5, willChange: 'transform' }} // GPU acceleration hint
    />
  );
}

// ============================================================================
// EPIC BIRTH SOUND - Web Audio API
// ============================================================================

function useBirthSound() {
  const audioContextRef = useRef<AudioContext | null>(null);
  const oscillatorsRef = useRef<OscillatorNode[]>([]);
  const gainNodesRef = useRef<GainNode[]>([]);

  const cleanup = useCallback(() => {
    console.log('[BirthSound] Cleaning up oscillators');
    oscillatorsRef.current.forEach(osc => {
      try { osc.stop(); osc.disconnect(); } catch {}
    });
    gainNodesRef.current.forEach(gain => {
      try { gain.disconnect(); } catch {}
    });
    oscillatorsRef.current = [];
    gainNodesRef.current = [];
  }, []);

  // Ensure AudioContext is resumed (browser requires user interaction)
  const ensureContext = useCallback(async () => {
    if (!audioContextRef.current) {
      audioContextRef.current = new AudioContext();
      console.log('[BirthSound] Created new AudioContext, state:', audioContextRef.current.state);
    }
    
    if (audioContextRef.current.state === 'suspended') {
      console.log('[BirthSound] Resuming suspended AudioContext...');
      await audioContextRef.current.resume();
      console.log('[BirthSound] AudioContext resumed, state:', audioContextRef.current.state);
    }
    
    return audioContextRef.current;
  }, []);

  const playTensionSound = useCallback(async () => {
    cleanup();
    console.log('[BirthSound] Playing tension sound...');
    
    try {
      const ctx = await ensureContext();

      // Create multiple oscillators for rich sound
      const baseFreq = 80;
      
      // Sub bass drone
      const subOsc = ctx.createOscillator();
      subOsc.type = 'sine';
      subOsc.frequency.setValueAtTime(baseFreq, ctx.currentTime);
      subOsc.frequency.linearRampToValueAtTime(baseFreq * 1.5, ctx.currentTime + 2.5);
      
      const subGain = ctx.createGain();
      subGain.gain.setValueAtTime(0, ctx.currentTime);
      subGain.gain.linearRampToValueAtTime(0.3, ctx.currentTime + 1);
      subGain.gain.linearRampToValueAtTime(0.5, ctx.currentTime + 2.5);
      
      subOsc.connect(subGain);
      subGain.connect(ctx.destination);
      
      // Rising tone
      const riseOsc = ctx.createOscillator();
      riseOsc.type = 'sawtooth';
      riseOsc.frequency.setValueAtTime(150, ctx.currentTime);
      riseOsc.frequency.exponentialRampToValueAtTime(800, ctx.currentTime + 2.5);
      
      const riseGain = ctx.createGain();
      riseGain.gain.setValueAtTime(0, ctx.currentTime);
      riseGain.gain.linearRampToValueAtTime(0.1, ctx.currentTime + 0.5);
      riseGain.gain.linearRampToValueAtTime(0.3, ctx.currentTime + 2.5);
      
      // Add filter for the rising tone
      const filter = ctx.createBiquadFilter();
      filter.type = 'lowpass';
      filter.frequency.setValueAtTime(300, ctx.currentTime);
      filter.frequency.exponentialRampToValueAtTime(2000, ctx.currentTime + 2.5);
      
      riseOsc.connect(filter);
      filter.connect(riseGain);
      riseGain.connect(ctx.destination);
      
      // Shimmer/sparkle effect
      const shimmerOsc = ctx.createOscillator();
      shimmerOsc.type = 'sine';
      shimmerOsc.frequency.setValueAtTime(2000, ctx.currentTime);
      shimmerOsc.frequency.linearRampToValueAtTime(4000, ctx.currentTime + 2.5);
      
      const shimmerGain = ctx.createGain();
      shimmerGain.gain.setValueAtTime(0, ctx.currentTime);
      shimmerGain.gain.linearRampToValueAtTime(0.05, ctx.currentTime + 1.5);
      shimmerGain.gain.linearRampToValueAtTime(0.15, ctx.currentTime + 2.5);
      
      shimmerOsc.connect(shimmerGain);
      shimmerGain.connect(ctx.destination);
      
      // Start all oscillators
      const startTime = ctx.currentTime;
      [subOsc, riseOsc, shimmerOsc].forEach(osc => osc.start(startTime));
      
      oscillatorsRef.current = [subOsc, riseOsc, shimmerOsc];
      gainNodesRef.current = [subGain, riseGain, shimmerGain];
      
    } catch (e) {
      console.log('[BirthSound] Web Audio not available:', e);
    }
  }, [cleanup, ensureContext]);

  const playExplosionSound = useCallback(async () => {
    cleanup();
    console.log('[BirthSound] Playing explosion sound...');
    
    try {
      const ctx = await ensureContext();

      // White noise burst
      const bufferSize = ctx.sampleRate * 0.5;
      const noiseBuffer = ctx.createBuffer(1, bufferSize, ctx.sampleRate);
      const output = noiseBuffer.getChannelData(0);
      for (let i = 0; i < bufferSize; i++) {
        output[i] = Math.random() * 2 - 1;
      }
      
      const noise = ctx.createBufferSource();
      noise.buffer = noiseBuffer;
      
      const noiseFilter = ctx.createBiquadFilter();
      noiseFilter.type = 'lowpass';
      noiseFilter.frequency.setValueAtTime(5000, ctx.currentTime);
      noiseFilter.frequency.exponentialRampToValueAtTime(200, ctx.currentTime + 0.5);
      
      const noiseGain = ctx.createGain();
      noiseGain.gain.setValueAtTime(0.4, ctx.currentTime);
      noiseGain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.5);
      
      noise.connect(noiseFilter);
      noiseFilter.connect(noiseGain);
      noiseGain.connect(ctx.destination);
      
      // Explosion impact - low thump
      const impactOsc = ctx.createOscillator();
      impactOsc.type = 'sine';
      impactOsc.frequency.setValueAtTime(150, ctx.currentTime);
      impactOsc.frequency.exponentialRampToValueAtTime(30, ctx.currentTime + 0.3);
      
      const impactGain = ctx.createGain();
      impactGain.gain.setValueAtTime(0.5, ctx.currentTime);
      impactGain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 0.4);
      
      impactOsc.connect(impactGain);
      impactGain.connect(ctx.destination);
      
      // Sparkle sweep
      const sparkleOsc = ctx.createOscillator();
      sparkleOsc.type = 'sine';
      sparkleOsc.frequency.setValueAtTime(4000, ctx.currentTime);
      sparkleOsc.frequency.exponentialRampToValueAtTime(800, ctx.currentTime + 1);
      
      const sparkleGain = ctx.createGain();
      sparkleGain.gain.setValueAtTime(0.2, ctx.currentTime);
      sparkleGain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + 1);
      
      sparkleOsc.connect(sparkleGain);
      sparkleGain.connect(ctx.destination);
      
      // Start
      noise.start(ctx.currentTime);
      impactOsc.start(ctx.currentTime);
      sparkleOsc.start(ctx.currentTime);
      
      // Schedule stop
      noise.stop(ctx.currentTime + 0.5);
      impactOsc.stop(ctx.currentTime + 0.5);
      sparkleOsc.stop(ctx.currentTime + 1);
      
    } catch (e) {
      console.log('[BirthSound] Explosion sound error:', e);
    }
  }, [cleanup, ensureContext]);

  const playAmbientHum = useCallback(async () => {
    cleanup();
    console.log('[BirthSound] Playing ambient hum...');
    
    try {
      const ctx = await ensureContext();

      // Gentle ambient hum
      const humOsc = ctx.createOscillator();
      humOsc.type = 'sine';
      humOsc.frequency.setValueAtTime(110, ctx.currentTime);
      
      const humGain = ctx.createGain();
      humGain.gain.setValueAtTime(0, ctx.currentTime);
      humGain.gain.linearRampToValueAtTime(0.05, ctx.currentTime + 1);
      
      // Very subtle modulation
      const lfoOsc = ctx.createOscillator();
      lfoOsc.type = 'sine';
      lfoOsc.frequency.setValueAtTime(0.5, ctx.currentTime);
      
      const lfoGain = ctx.createGain();
      lfoGain.gain.setValueAtTime(3, ctx.currentTime);
      
      lfoOsc.connect(lfoGain);
      lfoGain.connect(humOsc.frequency);
      
      humOsc.connect(humGain);
      humGain.connect(ctx.destination);
      
      humOsc.start(ctx.currentTime);
      lfoOsc.start(ctx.currentTime);
      
      oscillatorsRef.current = [humOsc, lfoOsc];
      gainNodesRef.current = [humGain];
      
    } catch (e) {
      console.log('[BirthSound] Ambient hum error:', e);
    }
  }, [cleanup, ensureContext]);

  const stop = useCallback(() => {
    // Fade out gracefully
    gainNodesRef.current.forEach(gain => {
      try {
        const ctx = audioContextRef.current;
        if (ctx) {
          gain.gain.linearRampToValueAtTime(0, ctx.currentTime + 0.3);
        }
      } catch {}
    });
    
    setTimeout(cleanup, 400);
  }, [cleanup]);

  useEffect(() => {
    return () => {
      cleanup();
      if (audioContextRef.current) {
        try { audioContextRef.current.close(); } catch {}
      }
    };
  }, [cleanup]);

  return { playTensionSound, playExplosionSound, playAmbientHum, stop };
}

