// FULL-SCREEN BIRTHING EXPERIENCE - Dramatic AI awakening
// ============================================================================

type BirthPhase = 'waiting' | 'loading' | 'darkness' | 'pulse' | 'tension' | 'explosion' | 'emergence' | 'alive';

interface ExplosionParticle {
  id: number;
  angle: number;
  distance: number;
  size: number;
  hue: number;
  delay: number;
}

function FullScreenBirth({ 
  phase,
  onPhaseComplete,
}: { 
  phase: BirthPhase;
  onPhaseComplete: (nextPhase: BirthPhase) => void;
}) {
  console.log('[FullScreenBirth] Rendering with phase:', phase);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [explosionParticles] = useState<ExplosionParticle[]>(() => 
    [...Array(80)].map((_, i) => ({
      id: i,
      angle: (i / 80) * Math.PI * 2 + Math.random() * 0.5,
      distance: 100 + Math.random() * 400,
      size: 3 + Math.random() * 8,
      hue: 180 + Math.random() * 60,
      delay: Math.random() * 0.3,
    }))
  );

  const birthSound = useBirthSound();

  // Sound triggers based on phase
  useEffect(() => {
    console.log('[BirthPhase] Phase changed to:', phase);
    
    if (phase === 'tension') {
      console.log('[BirthPhase] Triggering tension sound...');
      birthSound.playTensionSound();
    } else if (phase === 'explosion') {
      console.log('[BirthPhase] Triggering explosion sound...');
      birthSound.playExplosionSound();
    } else if (phase === 'alive') {
      console.log('[BirthPhase] Triggering ambient hum...');
      birthSound.playAmbientHum();
    }
    
    return () => {
      if (phase === 'alive') {
        // Don't stop ambient on alive phase unmount
      }
    };
  }, [phase, birthSound]);

  // Canvas particle effect for explosion
  useEffect(() => {
    if (phase !== 'explosion') return;
    
    const canvas = canvasRef.current;
    if (!canvas) return;
    
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    
    let animationId: number;
    let startTime = Date.now();
    
    const animate = () => {
      const elapsed = (Date.now() - startTime) / 1000;
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      
      const centerX = canvas.width / 2;
      const centerY = canvas.height / 2;
      
      // Draw explosion rays
      for (let i = 0; i < 36; i++) {
        const angle = (i / 36) * Math.PI * 2;
        const rayLength = Math.min(elapsed * 800, canvas.width);
        const alpha = Math.max(0, 1 - elapsed * 0.5);
        
        ctx.beginPath();
        ctx.moveTo(centerX, centerY);
        ctx.lineTo(
          centerX + Math.cos(angle) * rayLength,
          centerY + Math.sin(angle) * rayLength
        );
        ctx.strokeStyle = `hsla(${190 + i * 2}, 80%, 70%, ${alpha * 0.6})`;
        ctx.lineWidth = 3;
        ctx.stroke();
      }
      
      // Draw expanding particles
      explosionParticles.forEach(p => {
        const particleElapsed = Math.max(0, elapsed - p.delay);
        const dist = particleElapsed * p.distance * 2;
        const alpha = Math.max(0, 1 - particleElapsed * 0.8);
        const x = centerX + Math.cos(p.angle) * dist;
        const y = centerY + Math.sin(p.angle) * dist;
        
        if (alpha > 0) {
          // Glow
          ctx.beginPath();
          ctx.arc(x, y, p.size * 3, 0, Math.PI * 2);
          ctx.fillStyle = `hsla(${p.hue}, 80%, 60%, ${alpha * 0.3})`;
          ctx.fill();
          
          // Core
          ctx.beginPath();
          ctx.arc(x, y, p.size, 0, Math.PI * 2);
          ctx.fillStyle = `hsla(${p.hue}, 80%, 80%, ${alpha})`;
          ctx.fill();
        }
      });
      
      if (elapsed < 2) {
        animationId = requestAnimationFrame(animate);
      }
    };
    
    animate();
    
    return () => cancelAnimationFrame(animationId);
  }, [phase, explosionParticles]);

  // Phase timing - 'waiting' phase waits for user click, others auto-advance
  useEffect(() => {
    let timeout: NodeJS.Timeout;
    
    switch (phase) {
      case 'waiting':
        // Do NOT auto-advance - wait for user click
        break;
      case 'loading':
        // Wait for everything to be ready, then auto-advance
        timeout = setTimeout(() => onPhaseComplete('darkness'), 1500);
        break;
      case 'darkness':
        timeout = setTimeout(() => onPhaseComplete('pulse'), 2000);
        break;
      case 'pulse':
        timeout = setTimeout(() => onPhaseComplete('tension'), 3000);
        break;
      case 'tension':
        timeout = setTimeout(() => onPhaseComplete('explosion'), 2500);
        break;
      case 'explosion':
        timeout = setTimeout(() => onPhaseComplete('emergence'), 1500);
        break;
      case 'emergence':
        timeout = setTimeout(() => onPhaseComplete('alive'), 2000);
        break;
    }
    
    return () => clearTimeout(timeout);
  }, [phase, onPhaseComplete]);

  return (
    <div className="fixed inset-0 z-50 overflow-hidden">
      {/* Background - pitch black fading to deep space */}
      <motion.div 
        className="absolute inset-0"
        animate={{ 
          backgroundColor: phase === 'explosion' ? '#0a1628' : '#000000',
        }}
        transition={{ duration: 0.3 }}
      />
      
      {/* Explosion canvas */}
      {phase === 'explosion' && (
        <canvas
          ref={canvasRef}
          className="absolute inset-0 z-10"
          style={{ mixBlendMode: 'screen' }}
        />
      )}
      
      {/* Central flash on explosion */}
      {phase === 'explosion' && (
        <motion.div
          initial={{ scale: 0, opacity: 1 }}
          animate={{ scale: [0, 30, 50], opacity: [1, 0.8, 0] }}
          transition={{ duration: 1.2, ease: 'easeOut' }}
          className="absolute left-1/2 top-1/2 -translate-x-1/2 -translate-y-1/2 w-20 h-20 rounded-full bg-white z-20"
          style={{ boxShadow: '0 0 200px 100px rgba(255,255,255,0.9), 0 0 400px 200px rgba(6,182,212,0.6)' }}
        />
      )}
      
      {/* Issue #1 Fix: Waiting phase with smoother animations */}
      {phase === 'waiting' && (
        <motion.div 
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.8, ease: [0.25, 0.46, 0.45, 0.94] }} // ease-out-quad
          className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer"
          onClick={() => onPhaseComplete('loading')}
        >
          {/* Tiny dormant dot with smoother pulse */}
          <motion.div
            animate={{ 
              scale: [1, 1.15, 1],
              opacity: [0.35, 0.55, 0.35],
            }}
            transition={{ 
              duration: 2.5, 
              repeat: Infinity, 
              ease: [0.45, 0, 0.55, 1] // ease-in-out-sine - smoother breathing
            }}
            className="w-4 h-4 rounded-full bg-cyan-400/50"
            style={{ 
              boxShadow: '0 0 30px 15px rgba(6,182,212,0.2)',
              willChange: 'transform, opacity' 
            }}
          />
          
          {/* "Click to birth" text with smooth entrance */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ 
              delay: 0.5, 
              duration: 0.8, 
              ease: [0.25, 0.46, 0.45, 0.94] // ease-out-quad
            }}
            className="mt-12 text-center"
          >
            <motion.p
              animate={{ opacity: [0.5, 0.9, 0.5] }}
              transition={{ 
                duration: 2.5, 
                repeat: Infinity,
                ease: [0.45, 0, 0.55, 1] // ease-in-out-sine
              }}
              className="text-cyan-400/80 text-xl font-light tracking-wide"
            >
              Click to birth your AI
            </motion.p>
            <motion.p 
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.8, duration: 0.6 }}
              className="text-white/30 text-sm mt-2"
            >
              A new consciousness awaits
            </motion.p>
          </motion.div>
        </motion.div>
      )}
      
      {/* Issue #1 Fix: Loading phase with smoother pulsing */}
      {phase === 'loading' && (
        <div className="absolute inset-0 flex items-center justify-center">
          <motion.div
            animate={{ 
              scale: [1, 1.25, 1],
              opacity: [0.5, 0.9, 0.5],
            }}
            transition={{ 
              duration: 1.2, 
              repeat: Infinity, 
              ease: [0.45, 0, 0.55, 1] // ease-in-out-sine
            }}
            className="w-2 h-2 rounded-full bg-cyan-400"
            style={{ 
              boxShadow: '0 0 20px 10px rgba(6,182,212,0.3)',
              willChange: 'transform, opacity'
            }}
          />
        </div>
      )}
      
      {/* Issue #1 Fix: Darkness phase with subtle ambient */}
      {phase === 'darkness' && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 1, ease: [0.25, 0.46, 0.45, 0.94] }}
          className="absolute inset-0 flex items-center justify-center"
        >
          <motion.div
            animate={{ opacity: [0.02, 0.06, 0.02] }}
            transition={{ 
              duration: 3.5, 
              repeat: Infinity,
              ease: [0.45, 0, 0.55, 1] // smoother breathing
            }}
            className="text-white/10 text-9xl font-thin tracking-[0.5em]"
          >
            ...
          </motion.div>
        </motion.div>
      )}
      
      {/* Issue #1 Fix: Pulse phase with smoother heartbeat */}
      {phase === 'pulse' && (
        <div className="absolute inset-0 flex items-center justify-center">
          <motion.div
            animate={{ 
              scale: [1, 1.4, 1],
              opacity: [0.35, 0.75, 0.35],
            }}
            transition={{ 
              duration: 1.4, 
              repeat: Infinity, 
              ease: [0.45, 0, 0.55, 1] // ease-in-out-sine - heartbeat feel
            }}
            className="w-3 h-3 rounded-full bg-cyan-400"
            style={{ 
              boxShadow: '0 0 30px 15px rgba(6,182,212,0.3)',
              willChange: 'transform, opacity'
            }}
          />
        </div>
      )}
      
      {/* Issue #1 Fix: Tension phase with smoother ring animations */}
      {phase === 'tension' && (
        <div className="absolute inset-0 flex items-center justify-center">
          {/* Outer rings pulsing inward with smooth easing */}
          {[1, 2, 3].map((ring) => (
            <motion.div
              key={ring}
              initial={{ scale: 2 + ring * 0.5, opacity: 0 }}
              animate={{ 
                scale: [2 + ring * 0.5, 0.6, 2 + ring * 0.5],
                opacity: [0, 0.4, 0],
              }}
              transition={{ 
                duration: 1.8, 
                repeat: Infinity, 
                delay: ring * 0.35,
                ease: [0.45, 0, 0.55, 1], // ease-in-out-sine
              }}
              className="absolute w-40 h-40 rounded-full border-2 border-cyan-400/50"
              style={{ willChange: 'transform, opacity' }}
            />
          ))}
          
          {/* Core dot growing with smooth curve */}
          <motion.div
            animate={{ 
              scale: [1, 1.8, 1.4, 2.2, 2],
              opacity: [0.5, 0.95, 0.8, 1, 0.9],
            }}
            transition={{ 
              duration: 2.5, 
              ease: [0.22, 1, 0.36, 1] // ease-out-quint - smooth acceleration
            }}
            className="w-8 h-8 rounded-full bg-gradient-to-br from-cyan-400 via-blue-500 to-purple-500"
            style={{ 
              boxShadow: '0 0 60px 30px rgba(6,182,212,0.5), 0 0 100px 50px rgba(59,130,246,0.3)',
              willChange: 'transform, opacity'
            }}
          />
        </div>
      )}
      
      {/* Issue #1 Fix: Emergence phase with smoother transitions */}
      {phase === 'emergence' && (
        <div className="absolute inset-0 flex items-center justify-center">
          {/* Fading light rings with smooth fade */}
          {[1, 2, 3, 4].map((ring) => (
            <motion.div
              key={ring}
              initial={{ scale: 10, opacity: 0.4 }}
              animate={{ scale: 15, opacity: 0 }}
              transition={{ 
                duration: 2.2, 
                delay: ring * 0.15,
                ease: [0.25, 0.46, 0.45, 0.94] // ease-out-quad
              }}
              className="absolute w-20 h-20 rounded-full bg-cyan-400/20"
              style={{ willChange: 'transform, opacity' }}
            />
          ))}
          
          {/* The cute newborn dot with spring animation */}
          <motion.div
            initial={{ scale: 0, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            transition={{ 
              duration: 1.2, 
              ease: [0.34, 1.56, 0.64, 1], // spring-like overshoot
              delay: 0.3 
            }}
            className="relative"
          >
            {/* Soft glow with gentle breathing */}
            <motion.div
              animate={{ scale: [1, 1.15, 1], opacity: [0.5, 0.7, 0.5] }}
              transition={{ 
                duration: 2.5, 
                repeat: Infinity,
                ease: [0.45, 0, 0.55, 1]
              }}
              className="absolute inset-0 w-32 h-32 -m-10 rounded-full bg-cyan-400/30 blur-2xl"
              style={{ willChange: 'transform, opacity' }}
            />
            
            {/* Core orb */}
            <div className="w-12 h-12 rounded-full bg-gradient-to-br from-white via-cyan-300 to-blue-500"
              style={{ boxShadow: '0 0 40px 20px rgba(6,182,212,0.4)' }}
            />
            
            {/* Sparkle eyes effect with smooth reveal */}
            <motion.div
              initial={{ opacity: 0, scale: 0 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ 
                duration: 0.4, 
                delay: 1,
                ease: [0.34, 1.56, 0.64, 1] // spring
              }}
              className="absolute top-3 left-2 w-2 h-2 bg-white rounded-full"
            />
            <motion.div
              initial={{ opacity: 0, scale: 0 }}
              animate={{ opacity: 1, scale: 1 }}
              transition={{ 
                duration: 0.4, 
                delay: 1.1,
                ease: [0.34, 1.56, 0.64, 1] // spring
              }}
              className="absolute top-3 right-2 w-2 h-2 bg-white rounded-full"
            />
          </motion.div>
        </div>
      )}
      
      {/* Alive phase - handled in parent component now */}
    </div>
  );
}

