/**
 * ElevenLabs Text-to-Speech Hook
 * 
 * Provides TTS functionality throughout the onboarding experience.
 * Falls back to Web Speech API if ElevenLabs is unavailable.
 */

import { useState, useCallback, useRef, useEffect } from 'react';

// Voice options from ElevenLabs - these are real voice IDs
// Daniel is the default - British male, authoritative yet warm - highly rated
export const ELEVENLABS_VOICES = [
  { id: 'onwK4e9ZLuTAKqWW03F9', name: 'Daniel', description: 'British male, authoritative & warm', gender: 'male', previewText: "Hello! I'm Daniel. Ready to help you build something extraordinary together." },
  { id: 'JBFqnCBsd6RMkjVDRZzb', name: 'George', description: 'British male, calm & professional', gender: 'male', previewText: "Good day! I'm George. Let's make your business truly remarkable." },
  { id: 'N2lVS1w4EtoT3dr4eOWO', name: 'Callum', description: 'Scottish, warm & engaging', gender: 'male', previewText: "Hello there! I'm Callum. Excited to work alongside you!" },
  { id: 'pNInz6obpgDQGcFmaJgB', name: 'Adam', description: 'American, confident & clear', gender: 'male', previewText: "Hello! I'm Adam. Let's build something amazing together." },
  { id: 'cgSgspJ2msm6clMCkdW9', name: 'Jessica', description: 'Playful, bright & warm', gender: 'female', previewText: "Oh wow, hi! I'm Jessica! I'm so excited to meet you and help your team!" },
  { id: 'EXAVITQu4vr4xnSDxMaL', name: 'Bella', description: 'Warm & professional', gender: 'female', previewText: "Hi! I'm Bella. I can't wait to help your team succeed!" },
  { id: '21m00Tcm4TlvDq8ikWAM', name: 'Rachel', description: 'Friendly & approachable', gender: 'female', previewText: "Hi there! I'm Rachel. I'm here to make your life easier." },
] as const;

export type VoiceId = typeof ELEVENLABS_VOICES[number]['id'];

// Default voice ID - Daniel (British male, authoritative & warm) - highly rated
export const DEFAULT_VOICE_ID: VoiceId = 'onwK4e9ZLuTAKqWW03F9';

interface UseElevenLabsTTSOptions {
  defaultVoiceId?: VoiceId;
  onSpeakingChange?: (isSpeaking: boolean) => void;
  autoPlay?: boolean;
}

interface TTSState {
  isSpeaking: boolean;
  isLoading: boolean;
  error: string | null;
  currentVoiceId: VoiceId;
  queue: string[];
}

export function useElevenLabsTTS(options: UseElevenLabsTTSOptions = {}) {
  const { 
    defaultVoiceId = 'cgSgspJ2msm6clMCkdW9', // Jessica - playful, bright, warm
    onSpeakingChange,
    autoPlay = true,
  } = options;

  const [state, setState] = useState<TTSState>({
    isSpeaking: false,
    isLoading: false,
    error: null,
    currentVoiceId: defaultVoiceId,
    queue: [],
  });

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const abortControllerRef = useRef<AbortController | null>(null);
  const isMountedRef = useRef(true);

  // Cleanup on unmount
  useEffect(() => {
    isMountedRef.current = true;
    return () => {
      isMountedRef.current = false;
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
      if (abortControllerRef.current) {
        abortControllerRef.current.abort();
      }
    };
  }, []);

  // Notify when speaking state changes
  useEffect(() => {
    onSpeakingChange?.(state.isSpeaking);
  }, [state.isSpeaking, onSpeakingChange]);

  // Set voice
  const setVoice = useCallback((voiceId: VoiceId) => {
    setState(prev => ({ ...prev, currentVoiceId: voiceId }));
  }, []);

  // Stop current speech
  const stop = useCallback(() => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
    }
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    speechSynthesis.cancel();
    setState(prev => ({ ...prev, isSpeaking: false, isLoading: false, queue: [] }));
  }, []);

  // Speak using ElevenLabs API (or fallback to Web Speech)
  const speak = useCallback(async (text: string, voiceIdOverride?: VoiceId): Promise<void> => {
    if (!text.trim()) {
      console.log('[TTS] Empty text, skipping');
      return;
    }

    const voiceId = voiceIdOverride || state.currentVoiceId;
    const apiKey = import.meta.env.VITE_ELEVENLABS_API_KEY;

    // Bug Fix #5: Better debugging for ElevenLabs
    console.log('[TTS] ==================== SPEAK CALLED ====================');
    console.log('[TTS] Text:', text.substring(0, 80) + (text.length > 80 ? '...' : ''));
    console.log('[TTS] Voice ID:', voiceId);
    console.log('[TTS] API Key present:', !!apiKey);
    console.log('[TTS] API Key length:', apiKey?.length || 0);
    console.log('[TTS] API Key prefix:', apiKey ? apiKey.substring(0, 10) + '...' : 'MISSING');
    console.log('[TTS] All VITE_ env vars:', Object.keys(import.meta.env).filter(k => k.startsWith('VITE_')));
    console.log('[TTS] ======================================================');

    // Cancel any ongoing speech
    stop();

    setState(prev => ({ ...prev, isLoading: true, error: null }));

    // If no API key, use Web Speech API fallback
    if (!apiKey) {
      console.log('[TTS] No VITE_ELEVENLABS_API_KEY in env, using Web Speech fallback');
      console.log('[TTS] To enable ElevenLabs, add VITE_ELEVENLABS_API_KEY to frontend/.env.local');
      return new Promise((resolve) => {
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.rate = 1.0;
        utterance.pitch = 1.0;
        
        utterance.onstart = () => {
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: true, isLoading: false }));
          }
        };
        
        utterance.onend = () => {
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: false }));
          }
          resolve();
        };
        
        utterance.onerror = () => {
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: false, isLoading: false }));
          }
          resolve();
        };

        speechSynthesis.speak(utterance);
      });
    }

    // Use ElevenLabs API
    try {
      console.log('[TTS] Calling ElevenLabs API...');
      abortControllerRef.current = new AbortController();

      const response = await fetch(
        `https://api.elevenlabs.io/v1/text-to-speech/${voiceId}/stream`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'xi-api-key': apiKey,
          },
          body: JSON.stringify({
            text,
            model_id: 'eleven_turbo_v2_5',
            voice_settings: {
              stability: 0.5,
              similarity_boost: 0.75,
              style: 0.3,
              use_speaker_boost: true,
            },
          }),
          signal: abortControllerRef.current.signal,
        }
      );

      console.log('[TTS] ElevenLabs response status:', response.status);

      if (!response.ok) {
        const errorText = await response.text().catch(() => 'Unknown error');
        console.error('[TTS] ElevenLabs API error:', response.status, errorText);
        throw new Error(`ElevenLabs API error: ${response.status} - ${errorText}`);
      }

      const audioBlob = await response.blob();
      const audioUrl = URL.createObjectURL(audioBlob);

      return new Promise((resolve, reject) => {
        const audio = new Audio(audioUrl);
        audioRef.current = audio;

        audio.onplay = () => {
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: true, isLoading: false }));
          }
        };

        audio.onended = () => {
          URL.revokeObjectURL(audioUrl);
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: false }));
          }
          resolve();
        };

        audio.onerror = (e) => {
          URL.revokeObjectURL(audioUrl);
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: false, isLoading: false, error: 'Audio playback failed' }));
          }
          reject(e);
        };

        audio.play().catch((e) => {
          URL.revokeObjectURL(audioUrl);
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: false, isLoading: false, error: 'Failed to play audio' }));
          }
          reject(e);
        });
      });
    } catch (error: any) {
      if (error.name === 'AbortError') {
        console.log('[TTS] Speech aborted');
        return;
      }
      
      console.error('[TTS] ElevenLabs error, falling back to Web Speech:', error);
      
      // Fallback to Web Speech API
      return new Promise((resolve) => {
        const utterance = new SpeechSynthesisUtterance(text);
        utterance.rate = 1.0;
        utterance.pitch = 1.0;
        
        utterance.onstart = () => {
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: true, isLoading: false }));
          }
        };
        
        utterance.onend = () => {
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: false }));
          }
          resolve();
        };
        
        utterance.onerror = () => {
          if (isMountedRef.current) {
            setState(prev => ({ ...prev, isSpeaking: false, isLoading: false }));
          }
          resolve();
        };

        speechSynthesis.speak(utterance);
      });
    }
  }, [state.currentVoiceId, stop]);

  // Preview a specific voice
  const previewVoice = useCallback(async (voiceId: VoiceId): Promise<void> => {
    const voice = ELEVENLABS_VOICES.find(v => v.id === voiceId);
    if (voice) {
      await speak(voice.previewText, voiceId);
    }
  }, [speak]);

  // Speak multiple phrases in sequence
  const speakSequence = useCallback(async (texts: string[], delayMs = 500): Promise<void> => {
    for (const text of texts) {
      await speak(text);
      await new Promise(resolve => setTimeout(resolve, delayMs));
    }
  }, [speak]);

  return {
    // State
    isSpeaking: state.isSpeaking,
    isLoading: state.isLoading,
    error: state.error,
    currentVoiceId: state.currentVoiceId,
    
    // Actions
    speak,
    speakSequence,
    previewVoice,
    stop,
    setVoice,
    
    // Voices list
    voices: ELEVENLABS_VOICES,
  };
}
